/**
 * Unavailability Event Routes
 *
 * REST endpoints for managing train unavailability events (outages,
 * corrective maintenance, incidents). These events affect optimizer
 * constraints and train fitness status.
 *
 * @see specs/005-api.md Section 5.8
 * @see specs/004-domain-services.md Section 4.2.5
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getUnavailabilityService,
  type CreateEventRequest,
  type ResolveEventRequest,
  type EventListFilters,
} from '../../services/unavailability';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instance
let unavailabilityService: ReturnType<typeof getUnavailabilityService> | null = null;

function getService(): ReturnType<typeof getUnavailabilityService> {
  if (!unavailabilityService) {
    unavailabilityService = getUnavailabilityService();
  }
  return unavailabilityService;
}

export const unavailabilityRoutes = new Hono<{ Variables: AppVariables }>();

// =============================================================================
// Event CRUD
// =============================================================================

/**
 * POST /unavailability/events
 *
 * Create a new unavailability event for a train.
 * This will update the train's fitness status accordingly.
 *
 * Body:
 * - trainId: string (required) - UUID of the affected train
 * - eventType: string (required) - CORRECTIVE | INCIDENT | COLLISION | VANDALISM | EXTERNAL | PLANNED_OUTAGE
 * - restrictionLevel: string (required) - RESTRICTED | GROUNDED
 * - description: string (optional) - Event description
 * - failureCode: string (optional) - Failure code from CMMS
 * - affectedSystem: string (optional) - Affected train system
 * - estimatedRepairHours: number (optional) - Estimated repair time
 * - estimatedReturnDate: string (optional) - Expected return date (YYYY-MM-DD)
 * - sourceSystem: string (optional) - Source system (e.g., 'MAXIMO')
 * - externalReference: string (optional) - External reference (e.g., WO number)
 * - blocksPmScheduling: boolean (optional, default: true) - Prevents PM scheduling
 * - blocksRunAssignment: boolean (optional, default: true) - Prevents run assignment
 */
unavailabilityRoutes.post('/unavailability/events', async (c) => {
  const requestId = getRequestId(c);
  const body = await c.req.json();

  // Validate required fields
  if (!body.trainId || !isValidUuid(body.trainId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Valid trainId is required', requestId),
      400
    );
  }

  const validEventTypes = ['CORRECTIVE', 'INCIDENT', 'COLLISION', 'VANDALISM', 'EXTERNAL', 'PLANNED_OUTAGE'];
  if (!body.eventType || !validEventTypes.includes(body.eventType)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `eventType must be one of: ${validEventTypes.join(', ')}`,
        requestId
      ),
      400
    );
  }

  const validRestrictionLevels = ['RESTRICTED', 'GROUNDED'];
  if (!body.restrictionLevel || !validRestrictionLevels.includes(body.restrictionLevel)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `restrictionLevel must be one of: ${validRestrictionLevels.join(', ')}`,
        requestId
      ),
      400
    );
  }

/**
 * MMS Service Demand Service
 *
 * Manages fleet availability requirements - a CRITICAL v2.1 service.
 * Service demand is a HARD CONSTRAINT for the optimizer: schedules that
 * violate minimum train availability must be rejected.
 *
 * Key responsibilities:
 * - Define minimum train requirements by fleet, day type, and time period
 * - Validate that proposed PM schedules don't violate availability
 * - Calculate default demand (85% of fleet) when no explicit config exists
 * - Support peak period requirements (AM, midday, PM, evening)
 *
 * Business rules:
 * - Optimizer CANNOT schedule PM that would drop fleet below minTrainsRequired
 * - Day types: WEEKDAY, SATURDAY, SUNDAY, HOLIDAY
 * - Demand records are versioned by effectiveDate (most recent applies)
 * - Peak period requirements are optional but enforced if defined
 *
 * @see specs/003-database-schema.md Section 3.2.1 (Service Demand)
 * @see specs/004-domain-services.md Section 4.2.6 (Service Demand Service)
 */

