/**
 * MMS Ingestion Service
 *
 * Processes daily CSV files containing mileage data.
 * Validates records, handles meter events, and updates the database.
 *
 * Data flow:
 * 1. CSV file arrives via file watcher or API upload
 * 2. File is validated (format, size, structure)
 * 3. Records are parsed and validated in batches
 * 4. Anomalies are detected (NEGATIVE, SPIKE, DUPLICATE)
 * 5. Mileage readings are inserted/updated
 * 6. Train current_mileage_km is updated
 * 7. Fleet mileage targets are recalculated
 *
 * Business rules:
 * - Max file size: 10MB
 * - Expected file pattern: mileage_YYYYMMDD.csv
 * - Batch size: 100 records per transaction
 * - Anomaly thresholds: NEGATIVE < 0, SPIKE > 1000 km/day
 * - Meter adjustments are applied to maintain mileage continuity
 *
 * @see specs/004-domain-services.md Section 4.2
 */

import { eq, and, desc, lte, sql } from 'drizzle-orm';
import * as Papa from 'papaparse';
import * as fs from 'node:fs';
import * as path from 'node:path';
import { BaseService, MmsAttributes } from '../lib/services/base';
import { trains, mileageReadings, meterEvents } from '../lib/db/schema';
import {
  ValidationError,
  FileError,
  BusinessRuleError,
} from '../lib/errors';
import { parseMileageCsvRow } from '../lib/schemas';
import { addJob, QUEUE_NAMES, type IngestionJobData } from '../lib/queue';
import { ingestionMetrics, recordIngestionComplete, recordIngestionAnomaly } from '../lib/metrics';

// =============================================================================
// Constants
// =============================================================================

const MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024; // 10MB
const EXPECTED_FILE_PATTERN = /^mileage_\d{8}\.csv$/;
const BATCH_SIZE = 100;
const SPIKE_THRESHOLD_KM = 1000;
const ALERT_THRESHOLD_HOURS = 2;
const MISSING_GAP_THRESHOLD_DAYS = 3; // Flag if gap > 3 days between readings
const STATISTICAL_SPIKE_STDDEV_MULTIPLIER = 3; // Flag if > 3 standard deviations from mean

// =============================================================================
// Types
// =============================================================================

/** Anomaly types detected during ingestion */
export type AnomalyType = 'NEGATIVE' | 'SPIKE' | 'DUPLICATE' | 'MISSING' | 'FUTURE_DATE' | 'UNKNOWN_TRAIN';

/** A detected anomaly in the mileage data */
export interface AnomalyRecord {
  trainNumber: string;
  readingDate: string;
  type: AnomalyType;
  value: number | null;
  message: string;
  rawReading?: number;
  previousReading?: number;
}

/** Result of meter event detection */
export interface MeterEventRecord {
  trainNumber: string;
  trainId: string;
  eventDate: string;
  eventType: 'RESET' | 'REPLACEMENT' | 'CALIBRATION' | 'SWAP';
  oldReading: number;
  newReading: number;
  adjustmentKm: number;
}

